請對以下 Swift/AppKit 程式碼變更進行「程式碼品質」審查，找出 hacky patterns、冗餘狀態、抽象洩漏等問題。

## 重點變更

### ImageScrollView.swift 換頁邏輯重構
新增了以下狀態：
```swift
private var suppressScrollSequenceAfterPageTurn = false
private var suppressScrollAtTop = true  // true = 換到下一頁（強制停在 top）
private var isEnforcingScrollPosition = false
```

關鍵邏輯（scrollWheel 方法中）：
```swift
let isMomentumEvent = event.momentumPhase != []
let isTrackpad = event.phase != [] || isMomentumEvent
let isFreshTrackpadGesture = isTrackpad && event.phase == .began && !isMomentumEvent

func beginTrackpadGesture() {
    gestureBeganAtTop = isAtTop
    gestureBeganAtBottom = isAtBottom
    pageTurnedThisGesture = false
    overscrollAccumulator = 0
}

if isFreshTrackpadGesture {
    let wasSuppressed = suppressScrollSequenceAfterPageTurn
    let hadPageTurnLastGesture = pageTurnedThisGesture
    if wasSuppressed {
        suppressScrollSequenceAfterPageTurn = false
    }
    beginTrackpadGesture()
    if wasSuppressed || !hadPageTurnLastGesture {
        pageTurnLockUntil = 0
    }
} else if suppressScrollSequenceAfterPageTurn {
    super.scrollWheel(with: event)
    if event.momentumPhase == .ended || event.momentumPhase == .cancelled || !isTrackpad {
        suppressScrollSequenceAfterPageTurn = false
    }
    return
}

if CACurrentMediaTime() < pageTurnLockUntil {
    return
}
```

`reflectScrolledClipView` override：
```swift
override func reflectScrolledClipView(_ cView: NSClipView) {
    super.reflectScrolledClipView(cView)
    guard suppressScrollSequenceAfterPageTurn, !isEnforcingScrollPosition,
          let docView = documentView else { return }
    let yBounds = yScrollBounds(docHeight: docView.frame.height, clipHeight: cView.bounds.height, insets: contentInsets)
    let targetY = suppressScrollAtTop ? yBounds.max : yBounds.min
    let currentY = cView.bounds.origin.y
    if abs(currentY - targetY) > Constants.scrollPositionClampTolerance {
        isEnforcingScrollPosition = true
        cView.setBoundsOrigin(NSPoint(x: cView.bounds.origin.x, y: targetY))
        isEnforcingScrollPosition = false
    }
}
```

`commitPageTurn` 方法：
```swift
private func commitPageTurn(goingDown: Bool) {
    pageTurnedThisGesture = true
    overscrollAccumulator = 0
    suppressScrollAtTop = goingDown
    suppressScrollSequenceAfterPageTurn = true
    pageTurnLockUntil = CACurrentMediaTime() + pageTurnLockDuration
    NSApp.discardEvents(matching: .scrollWheel, before: nil)
    if goingDown {
        scrollDelegate?.scrollViewDidReachBottom(self)
    } else {
        scrollDelegate?.scrollViewDidReachTop(self)
    }
}
```

### `isAtTop/isAtBottom` 判斷修正
舊：
```swift
isAtTop = clipBounds.maxY >= docFrame.height - edgeThreshold
isAtBottom = clipBounds.minY <= edgeThreshold
```
新：
```swift
let yBounds = yScrollBounds(docHeight: docFrame.height, clipHeight: clipBounds.height, insets: contentInsets)
isAtTop = clipBounds.minY >= yBounds.max - edgeThreshold
isAtBottom = clipBounds.minY <= yBounds.min + edgeThreshold
```

### ImageViewController.swift - fitOnScreen 內聯邏輯
```swift
@objc func fitOnScreen(_ sender: Any? = nil) {
    settings.isManualZoom = false
    if let imageSize = currentDocumentSize {
        let viewport = effectiveScrollViewport
        if viewport.width > 0, viewport.height > 0 {
            let fitted = FittingCalculator.calculate(imageSize: imageSize, viewportSize: viewport, options: settings.fittingOptions)
            setMagnificationCentered(fitted.width / imageSize.width)
            updateScalingQuality()
            applyCenteringInsetsIfNeeded(reason: "fitOnScreen")
        }
    }
    settings.save()
    scheduleResizeToFitAfterZoom(magnification: scrollView.magnification)
}
```

### ViewerSettings.swift - trackpad 閾值調整
```swift
var trackpadThreshold: CGFloat {
    switch self {
    case .low:    return 250  // was 200
    case .medium: return 160  // was 130
    case .high:   return 80   // was 60
    }
}
```

### 新 Constants
```swift
static let scrollPositionClampTolerance: CGFloat = 1.0
```

## 審查任務
請在 /Users/pc035860/code/cee 目錄審查：
1. `suppressScrollAtTop` 狀態是否冗餘？它的值總是等於 `commitPageTurn(goingDown:)` 的參數，是否可以改為直接存取換頁方向？
2. `beginTrackpadGesture` 是一個 local func 在 `scrollWheel` 方法中——這是否合適，還是應該是 private method？
3. `isFreshTrackpadGesture` 分支中的邏輯是否清晰？`wasSuppressed` + `hadPageTurnLastGesture` 組合條件的語意是否清楚？
4. `fitOnScreen` 不再呼叫 `applyFitting`，但仍有其他 11 個地方呼叫 `applyFitting`。新的 fitOnScreen 是否遺漏了什麼？（注意 `applyFitting` 還有 `imageSize.width > 0, imageSize.height > 0` guard，新版沒有）
5. i18n 的 context menu 中新增了 `toggleSinglePageRTLNavigation` 項目——是否符合原有設計意圖？

請搜尋相關檔案並給出具體修改建議，包含 file_path:line_number。

