465→    private func panDown() {
466→        let clip = contentView
467→        let yBounds = yScrollBounds(docHeight: documentView?.frame.height ?? 0, clipHeight: clip.bounds.height, insets: contentInsets)
468→        let newY = max(clip.bounds.minY - Constants.arrowPanStep, yBounds.min)
469→        animateScroll(to: NSPoint(x: clip.bounds.minX, y: newY))
